+
+            let dfs = dfs_tree(py, graph.bind(py).as_any(), None, None, None)
+                .expect("dfs tree should succeed");
+            assert_eq!(dfs.inner.mode(), CompatibilityMode::Hardened);
+            assert_eq!(
+                dfs.inner.runtime_policy().mode(),
+                CompatibilityMode::Hardened
+            );
+        });
+    }
